import React, { useEffect } from "react";
import styles from "./product-details.module.css";
import GridLayout from "../layout/grid-layout";
import ProductPresentation from "./product-presentation";
import ProductInfo from "./product-info";
import { useParams } from "react-router-dom";
import { useAppDispatch } from "../../app/hooks";
import { setProductDetails } from "../../app/productSlice";
import productsData from "../homepage/product-listing/product.json";

const ProductDetails: React.FC = () => {
  const { productId } = useParams();
  const dispatch = useAppDispatch();

  const thisProduct = productsData.find((prod) => prod.id === Number(productId));

  useEffect(() => {
    if (thisProduct) {
      dispatch(setProductDetails(thisProduct));
    }
  }, [productId, dispatch, thisProduct]);

  // Render the product details
  if (!thisProduct) {
    return <div>Product not found</div>;
  }

  return (
    <div className={styles.product}>
      <div className="container">
        <GridLayout>
          <div className="left-side">
            <ProductPresentation imgSrc={thisProduct.img} />
          </div>
          <div className={styles.right_side}>
            {/* Pass the 'thisProduct' directly to 'ProductInfo' */}
            <ProductInfo product={thisProduct} />
          </div>
        </GridLayout>
      </div>
    </div>
  );
};

export default ProductDetails;







